}

/// <summary>
/// Initializes the <c>CustQuotationJour</c> table with <c>SalesQuotationTable</c> table.
/// </summary>
/// <param name="_args">The event arguments.</param>
[PostHandlerFor(tableStr(CustQuotationJour), tableMethodStr(CustQuotationJour, initFromSalesQuotationTable))]
public static void CustQuotationJour_Post_initFromSalesQuotationTable(XppPrePostArgs _args)
{
    CustQuotationJour       custQuotationJour = _args.getThis() as CustQuotationJour;
    SalesQuotationTable     salesQuotationTable = _args.getArg(identifierStr(_salesQuotationTable)) as SalesQuotationTable;

    custQuotationJour.FWFTextBlockQuotationIdFrom = salesQuotationTable.QuotationId;
}

/// <summary>
/// Initializes the <c>SalesLine</c> table with <c>SalesQuotationLine</c> table.
/// </summary>
/// <param name="_args">The event arguments.</param>
[PostHandlerFor(tableStr(SalesLine), tableMethodStr(SalesLine, initFromSalesQuotationLine))]
public static void SalesLine_Post_initFromSalesQuotationLine(XppPrePostArgs _args)
{
    SalesLine           salesLine = _args.getThis() as SalesLine;
    SalesQuotationLine  salesQuotationLine = _args.getArg(identifierStr(_salesQuotationLine)) as SalesQuotationLine;
    SalesQuotationLine	salesQuotationLineCheck;

    // to ensure it's not a fake RecId in case of project quotation
    salesQuotationLineCheck = SalesQuotationLine::findRecId(salesQuotationLine.RecId);
    if (!salesQuotationLineCheck)
    {
        salesQuotationLine = SalesQuotationLine::findInventTransId(salesQuotationLine.InventTransId);
    }

    salesLine.FWFTextBlockQuotationLineRefRecId = salesQuotationLine.RecId;
}

/// <summary>
/// Initializes the <c>CustQuotationConfirmJour</c> table with <c>SalesQuotationTable</c> table.
/// </summary>
/// <param name="_args">The event arguments.</param>
[PostHandlerFor(tableStr(CustQuotationConfirmJour), tableMethodStr(CustQuotationConfirmJour, initFromSalesQuotationTable))]
public static void CustQuotationConfirmJour_Post_initFromSalesQuotationTable(XppPrePostArgs _args)
{
    CustQuotationConfirmJour custQuotationConfirmJour = _args.getThis() as CustQuotationConfirmJour;
    SalesQuotationTable salesQuotationTable = _args.getArg(identifierStr(_salesQuotationTable)) as SalesQuotationTable;

    custQuotationConfirmJour.FWFTextBlockQuotationIdFrom = salesQuotationTable.QuotationId;
}

/// <summary>
/// Returns the default language id. This is primary the language id of legal entity, secondary the system langauge id.
/// </summary>
/// <returns>The <c>LanguageId</c> value.</returns>
public LanguageId getDefaultLanguageId()
{
    LanguageId languageId = CompanyInfo::find().LanguageId;
    ;
    if (!languageId)
    {
        languageId = SystemParameters::find().SystemLanguageId;
    }

    return languageId;
}
